#!/bin/bash\n\n# OpenVPN 一键安装脚本 (适用于 Ubuntu)\n# 该脚本将安装 OpenVPN，配置服务器，并生成一个客户端配置文件 (client1.ovpn)。\n# 请注意：此脚本应在具有公网 IP 的 Ubuntu 服务器上以 root 用户或具有 sudo 权限的用户运行。\n# 运行方式: sudo bash setup_openvpn.sh <your_public_ip>\n\nset -e # 遇到错误时退出\n\n# --- 配置部分 ---\n# 从命令行参数获取公网 IP\nPUBLIC_IP=\"$1\"\nif [[ -z \"$PUBLIC_IP\" ]]; then\n  echo \"用法: sudo bash $0 <your_public_ip>\"\n  echo \"请提供服务器的公网 IP 地址。\"\n  exit 1\nfi\n\n# OpenVPN 端口和协议\nPORT=1194\nPROTO=udp\n\n# VPN 网络配置\nVPN_SUBNET=\"10.8.0.0\"\nVPN_NETMASK=\"255.255.255.0\"\nVPN_DHCP_START=\"10.8.0.2\"\nVPN_DHCP_END=\"10.8.0.254\"\n\n# DNS 服务器 (可修改为您偏好的 DNS)\nDNS1=\"8.8.8.8\"\nDNS2=\"8.8.4.4\"\n\n# --- 安装 OpenVPN 和 Easy-RSA ---\necho \"正在更新包列表...\"\napt update\n\necho \"正在安装 OpenVPN 和 Easy-RSA...\"\napt install -y openvpn easy-rsa\n\n# --- 设置 PKI 和生成证书 ---\necho \"正在设置 PKI 和生成证书...\"\nmake-cadir /etc/openvpn/easy-rsa\ncd /etc/openvpn/easy-rsa\n\n# 修改 vars 文件 (使用默认值，如果需要自定义，请编辑此部分)\ncat > vars <<EOF\nexport KEY_COUNTRY=\"CN\"\nexport KEY_PROVINCE=\"Beijing\"\nexport KEY_CITY=\"Beijing\"\nexport KEY_ORG=\"MyOrg\"\nexport KEY_EMAIL=\"admin@example.com\"\nexport KEY_OU=\"MyOrgUnit\"\nexport KEY_NAME=\"server\"\nEOF\n\n# 初始化 PKI\nsource ./vars\n./clean-all\n\n# 构建 CA (自动回答 yes)\necho -e \"\\n\\n\\n\\n\\n\\n\\n\" | ./build-ca\n\n# 构建服务器证书 (自动回答 yes)\necho -e \"\\n\\n\\n\\n\\n\\n\\n\\n\\n\" | ./build-key-server server\n\n# 生成 Diffie-Hellman 参数\n./build-dh\n\n# 生成 HMAC 签名\nopenvpn --genkey --secret keys/ta.key\n\n# 构建客户端证书 (client1) (自动回答 yes)\necho -e \"\\n\\n\\n\\n\\n\\n\\n\\n\\n\" | ./build-key client1\n\n# --- 配置 OpenVPN 服务器 ---\necho \"正在配置 OpenVPN 服务器...\"\ncd /etc/openvpn\n\n# 复制证书和密钥\ncp /etc/openvpn/easy-rsa/keys/{ca.crt,server.crt,server.key,ta.key,dh2048.pem} /etc/openvpn/server/\n\n# 创建服务器配置文件\ncat > /etc/openvpn/server/server.conf <<EOF\nport $PORT\nproto $PROTO\ndev tun\n\nca /etc/openvpn/server/ca.crt\ncert /etc/openvpn/server/server.crt\nkey /etc/openvpn/server/server.key\ndh /etc/openvpn/server/dh2048.pem\ntls-auth /etc/openvpn/server/ta.key 0\n\ntopology subnet\nserver $VPN_SUBNET $VPN_NETMASK\n\npush \"redirect-gateway def1 bypass-dhcp\"\npush \"dhcp-option DNS $DNS1\"\npush \"dhcp-option DNS $DNS2\"\n\nkeepalive 10 120\ncipher AES-256-CBC\nauth SHA256\n\nuser nobody\ngroup nogroup\n\npersist-key\npersist-tun\n\nstatus openvpn-status.log\nverb 3\nEOF\n\n# --- 配置防火墙和网络 ---\necho \"正在配置防火墙和网络...\"\n# 允许 OpenVPN 端口通过 UFW (如果启用)\nif command -v ufw &> /dev/null; then\n    ufw allow $PORT/$PROTO\nfi\n\n# 启用 IP 转发 (临时)\necho 1 > /proc/sys/net/ipv4/ip_forward\n# 永久启用 IP 转发\necho 'net.ipv4.ip_forward=1' >> /etc/sysctl.conf\n\n# 配置 NAT (假设公网接口是 eth0, 如果不是，请修改)\n# 注意：此脚本假设最常见的以太网接口名。如果您的接口名不同（例如 ens3, enp0s3），请修改下面的 eth0。\n# 您可以使用 `ip a` 命令查看接口名称。\nINTERFACE=$(ip route | grep default | awk '{print $5}' | head -n 1)\nif [[ -z \"$INTERFACE\" ]]; then\n    INTERFACE=\"eth0\" # 默认 fallback\nfi\necho \"检测到的默认网络接口: $INTERFACE\"\n\n# 应用 iptables 规则\niptables -t nat -A POSTROUTING -s $VPN_SUBNET/$VPN_NETMASK -o $INTERFACE -j MASQUERADE\niptables -A FORWARD -i tun0 -j ACCEPT\niptables -A FORWARD -i $INTERFACE -o tun0 -m state --state RELATED,ESTABLISHED -j ACCEPT\n\n# 保存 iptables 规则 (安装 iptables-persistent 并保存)\napt install -y iptables-persistent\niptables-save > /etc/iptables/rules.v4\n\n# --- 启动 OpenVPN 服务 ---\necho \"正在启动 OpenVPN 服务...\"\nsystemctl start openvpn@server\nsystemctl enable openvpn@server\n\n# --- 生成客户端配置文件 ---\necho \"正在生成客户端配置文件 (client1.ovpn)...\"\ncd /root # 将客户端配置文件放在 root 用户主目录下\n\n# 创建 .ovpn 文件\ncat > client1.ovpn <<EOF\nclient\ndev tun\nproto $PROTO\nremote $PUBLIC_IP $PORT\nresolv-retry infinite\nnobind\npersist-key\npersist-tun\nremote-cert-tls server\ncipher AES-256-CBC\nauth SHA256\nverb 3\n\n<ca>\n$(cat /etc/openvpn/easy-rsa/keys/ca.crt)\n</ca>\n\n<cert>\n$(cat /etc/openvpn/easy-rsa/keys/client1.crt)\n</cert>\n\n<key>\n$(cat /etc/openvpn/easy-rsa/keys/client1.key)\n</key>\n\n<tls-auth>\n$(cat /etc/openvpn/easy-rsa/keys/ta.key)\n</tls-auth>\nkey-direction 1\nEOF\n\necho \"\"\necho \"OpenVPN 服务器安装和配置完成！\"\necho \"\"\necho \"客户端配置文件已生成: /root/client1.ovpn\"\necho \"请将此文件下载到您的设备（如 iPhone）并使用 OpenVPN Connect 应用导入。\"\necho \"\"\necho \"服务器状态:\"\nsystemctl status openvpn@server --no-pager -l